// MRFGrooveSweepFeature : SetInput3DCurve
//input: const CATBaseUnknown_var &input3dCurve
//Function: Sets the input 3DCurve into feature
//-----------------------------------------------------------------------------
HRESULT MRFGrooveSweep::SetInput3DCurve(const CATBaseUnknown_var &isp3dCurve)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnGrooveSweep(_CredentialForCC, this);

	if ((isp3dCurve != NULL_var) && (!!FeatFacadeOnGrooveSweep))//Check input
	{
		// Valuate attribute key
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValue;

		AttrKey = CATFmAttributeName(_MRFGrooveInput3DCurve);
		rc = FeatFacadeOnGrooveSweep.GetValue(AttrKey, FmAttrValue);
		FeatFacadeOnGrooveSweep.UnsetValue(AttrKey);

		// Get input Curve feature facade
		CATFmFeatureFacade FeatFacadeOnCurve;
		FeatFacadeOnCurve = isp3dCurve;

		if (!!FeatFacadeOnCurve && SUCCEEDED(rc))
		{
			FmAttrValue.Clear();
			FmAttrValue.SetFeature(FeatFacadeOnCurve);

			// Set the feature attribute
			rc = FeatFacadeOnGrooveSweep.SetValue(AttrKey, FmAttrValue);
			if (SUCCEEDED(rc))
			{
        //UpdateFeature();
      }
		}
	}
	return rc;
}

