//-----------------------------------------------------------------------------
// MRFGrooveSweep : SetExtrapolateTrim
//input: int iExtrapolateIndex
//Function: Sets the input ExtrapolateTrim into feature
//-----------------------------------------------------------------------------
HRESULT MRFGrooveSweep::SetExtrapolateTrim(const int & iExtrapolateIndex)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnPV(_CredentialForCC, this);

	if ((iExtrapolateIndex >= 0) && (!!FeatFacadeOnPV))
	{
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValue;

		AttrKey = CATFmAttributeName(_MRFGrooveExtrapolateTrim);
		rc = FeatFacadeOnPV.GetValue(AttrKey, FmAttrValue);
		FeatFacadeOnPV.UnsetValue(AttrKey);

		if (SUCCEEDED(rc))
		{
			FmAttrValue.Clear();
			FmAttrValue.SetInteger(iExtrapolateIndex);

			rc = FeatFacadeOnPV.SetValue(AttrKey, FmAttrValue);
		}
	}
	return rc;
}

