//-----------------------------------------------------------------------------
// MRFGrooveSweepFeature : UpdateFeature
//Function: update the created feature.
//-----------------------------------------------------------------------------
void MRFGrooveSweep::UpdateFeature()
{
	CATFmFeatureFacade FeatFacadeOnGrooveSweep(_CredentialForCC, this);
	HRESULT rc = FeatFacadeOnGrooveSweep.IsUpToDate();
	if (S_FALSE == rc)
	{
		rc = FeatFacadeOnGrooveSweep.Update();
		if (SUCCEEDED(rc))
		{
			CATBaseUnknown * pGroveSweepObject = NULL;
			rc = FeatFacadeOnGrooveSweep.QueryInterfaceOnFeature(IID_CATBaseUnknown, (void**)&pGroveSweepObject);
			if (SUCCEEDED(rc) && NULL != pGroveSweepObject)
			{
				CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(pGroveSweepObject);

				pGroveSweepObject->Release();
				pGroveSweepObject = NULL;
			}
		}
	}
}